import React, { useEffect, useState } from 'react'
import { Container, TextField, Typography } from '@mui/material';

import '../static/css/PoemListing.css';

import Data from '../utils/Data';

import Header from '../components/general/Header';
import Footer from '../components/general/Footer';

import PoemList from '../components/poems/PoemList';
import PoemTiles from '../components/poems/PoemTiles';

import T from '../api/T';

type Props = {}

type Poem = {
    url: string,
    id: string,
    title: string
}

const Poems = (props: Props) => {
    const [poems, setPoems] = useState([])
    const [display, setDisplay] = useState([])

    useEffect(() => {
        const getPoems = async () => {
            const serverData = await fetchPoems()
            setPoems(serverData)
            setDisplay(serverData)
        }
        getPoems()
    }, [])

    const fetchPoems = async () => {
        const res = await fetch(Data.fetchPoemList)
        const json = await res.json()
        return json
    }

    const searchPoem = (e: any) => {
        const query = e.target.value;
        const temp: [] = []
        for (let index = 0; index < poems.length; index++) {
            if ((poems[index] as Poem).title.toLowerCase().includes(query.toLowerCase()) || query.toLowerCase().includes((poems[index] as Poem).id)) {
                temp.push(poems[index])
            }
        }
        setDisplay(temp)
    }

    return (
        <>
            <Container maxWidth="lg">
                <Header title="Rafist0" sections={Data.sections} />
                <main>
                    <div className="listpagemain" style={{}}>
                        <Typography variant="h4" style={{ marginBlockEnd: "15px" }}>{T("poem.list")}</Typography>
                        <Typography sx={{ margin: "auto" }} maxWidth="sm">{T("poem.list.greeting")}</Typography>
                        <div className="recordcontainerparent">
                            <TextField
                                id="__poemsearch"
                                label={T("poems.poem.search")}
                                type="search"
                                variant="filled"
                                fullWidth
                                InputProps={{
                                    inputProps: {
                                        style: { textAlign: "center" },
                                    }
                                }}
                                style={{ display: "inline-block" }}
                                onChange={(e) => { searchPoem(e) }}></TextField>
                            <div id="poemlist">
                                <PoemList display={display}/>
                            </div>
                            <div id="poemtiles">
                                <PoemTiles display={display}/>
                            </div>
                        </div>
                    </div>
                </main>
            </Container>
            <Footer
                title={T("poem.project")}
                description={T("footer.msg")}
            />
        </>
    )
}

export default Poems