import { Button, Link, Paper, Table, TableBody, TableCell, TableContainer, TableHead, TableRow } from '@mui/material'
import React from 'react'
import T from '../../api/T'

type PoemElement = {
  url: string,
  id: string,
  date: string,
  title: string,
  description: string
}

type Props = {
  display: any
}

const List = (props: Props) => {
  return (
    <TableContainer component={Paper}>
      <Table sx={{ minWidth: 650 }} aria-label="simple table">
        <TableHead>
          <TableRow>
          <TableCell>{T("poemlist.id")}</TableCell>
          <TableCell>{T("poemlist.title")}</TableCell>
          <TableCell>{T("poemlist.date")}</TableCell>
          <TableCell>{T("poemlist.description")}</TableCell>
          <TableCell>{T("poemlist.readonline")}</TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {props.display.sort().map((poem: PoemElement) => (
            <TableRow
            key={poem["id"]}
            sx={{ '&:last-child td, &:last-child th': { border: 0 },textDecoration: 'none' }}
            component={Link} href={poem["url"] ? "/#/poems/"+ poem["url"] : "none"}
            >
            <TableCell component="th" scope="row">{poem["id"]}</TableCell>
            <TableCell>{poem["title"]}</TableCell>
            <TableCell>{poem["date"]}</TableCell>
            <TableCell>{poem["description"]}</TableCell>
            <TableCell>
            <Link sx={{textDecoration: 'none'}} href={poem["url"] ? "/#/poems/"+ poem["url"] : "none"}>
              <Button style={{margin:"5px"}} variant="outlined">{poem["title"]}</Button>
            </Link>
            </TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  )
}

export default List