import * as React from 'react';
import Data from '../utils/Data';
import Grid from '@mui/material/Grid';
import Container from '@mui/material/Container';
import GitHubIcon from '@mui/icons-material/GitHub';
import FacebookIcon from '@mui/icons-material/Facebook';
import TwitterIcon from '@mui/icons-material/Twitter';
import Header from '../components/general/Header';
import MainFeaturedPost from '../components/blog/MainFeaturedPost';
import FeaturedPost from '../components/blog/FeaturedPost';
import Sidebar from '../components/blog/Sidebar';
import Footer from '../components/general/Footer';
import { useEffect, useState } from 'react';
import { Divider, TextField } from '@mui/material';
import T from '../api/T';
import ArticleListing from '../components/blog/ArticleListing';

const sidebar = {
  title: 'Informacja',
  description:
    'Specjalnie dla tych, którzy wyrażą chęć czytania mojej twórczości, prezentuję stronę internetową, dzięki której w prosty sposób można przeglądać moją twórczość. Życzę miłego czytania!',
  archives: [
    { title: 'March 2020', url: '#' },
    { title: 'February 2020', url: '#' },
    { title: 'January 2020', url: '#' },
    { title: 'November 1999', url: '#' },
    { title: 'October 1999', url: '#' },
    { title: 'September 1999', url: '#' },
    { title: 'August 1999', url: '#' },
    { title: 'July 1999', url: '#' },
    { title: 'June 1999', url: '#' },
    { title: 'May 1999', url: '#' },
    { title: 'April 1999', url: '#' },
  ],
  social: [
    { name: 'GitHub', icon: GitHubIcon },
    { name: 'Twitter', icon: TwitterIcon },
    { name: 'Facebook', icon: FacebookIcon },
  ],
};

const baseArticles = [
  {
    url: "basearticle",
    title: 'Tytuł Głównego Artykułu',
    description: "W podanym opisie znajdą się najważniejsze informacje dotyczące artykułu.",
    image: '',
    date: "1 I 1970 RW",
    imageText: 'Opis zdjęcia do głównego artykułu',
    imageLabel: 'Opis zdjęcia do głównego artykułu',
    linkText: 'Kontynuuj czytanie...',
  },
  {
    url: "proceedingarticle",
    title: 'Tytuł Następnego Artykułu',
    description: "W podanym opisie znajdą się najważniejsze informacje dotyczące artykułu.",
    image: '',
    date: "1 I 1970 RW",
    imageText: 'Opis zdjęcia do głównego artykułu',
    imageLabel: 'Opis zdjęcia do głównego artykułu',
    linkText: 'Kontynuuj czytanie...',
  }
]

export default function Articles() {
  const [articles, setArticles] = useState(baseArticles)
  const [display, setDisplay] = useState(baseArticles)

  useEffect(() => {
    const getArticles = async () => {
      const serverData = await fetchArticles()
      setArticles(serverData)
      setDisplay(serverData)
    }
    getArticles()
  }, [])

  const fetchArticles = async () => {
    const res = await fetch(Data.fetchArticleList)
    const json = await res.json()
    return json
  }

  const searchArticle = (e: any) => {
    const query = e.target.value;
    const temp = [];
    for (let index = 0; index < articles.length; index++) {
      if ((articles[index].title.toLowerCase().includes(query.toLowerCase()) || query.toLowerCase().includes((articles[index].description)))) {
        temp.push(articles[index]);
      }
    }
    setDisplay(temp);
  }

  return (
    <>
      <Container maxWidth="lg">
        <Header title="Rafist0" sections={Data.sections} />
        <main>
          <MainFeaturedPost post={articles[0]} />
          <Grid container spacing={4}>
            {articles.slice(1, 3).map((post) => (
              <FeaturedPost key={post.title} post={post} />
            ))}
          </Grid>
          <Grid container spacing={5} sx={{ mt: 3 }}>
            <Grid item xs={12} md={8}>
              <Divider variant="middle">{T("articles.all")}</Divider>
              <div style={{ marginLeft: "1rem" }}>
                {display.map((post) => (
                  <ArticleListing post={post}/>
                ))}
              </div>
            </Grid>
            <Grid item xs={12} md={4}>
              <TextField
                id="__poemsearch"
                label={T("articles.search")}
                type="search"
                variant="filled"
                fullWidth
                InputProps={{
                  inputProps: {
                    style: { textAlign: "center" },
                  }
                }}
                style={{ display: "inline-block" }}
                onChange={(e) => { searchArticle(e) }}>
              </TextField>
            </Grid>
            <div style={{ display: "none" }}>
              <Sidebar
                title={sidebar.title}
                description={sidebar.description}
                archives={sidebar.archives}
                social={sidebar.social}
              />
            </div>
          </Grid>
        </main>
      </Container>
      <Footer
        title={T("articles.project")}
        description={T("footer.msg")}
      />
    </>
  );
}
