import { Link, Typography } from '@mui/material'
import React from 'react'

type Post = {
    post: {
        url: string;
        title: string;
        description: string;
        image: string;
        date: string;
        imageText: string;
        imageLabel: string;
        linkText: string;
    } 
}

const ArticleListing = (props: Post) => {
    let flag = "🇵🇱";
    if (props.post.url.startsWith('en.')){
        flag = "🇺🇸";
    }
    return (
        <div style={{ paddingBottom: "10px" }} key={props.post.title}>
            <Link sx={{ color: "#fff", fontSize: "15pt", textDecoration: 'none' }} className="" href={"#/articles/" + props.post.url}>{flag} {props.post.title} [{props.post.date}]</Link>
            <br />
            <Typography sx={{ fontStyle: "italic", fontSize: "12pt" }}>{props.post.description}</Typography>
        </div>
    )
}

export default ArticleListing