import { Button, Grid } from '@mui/material'
import React from 'react'
import { GlobalStateInterface, useGlobalState } from '../../hooks/GlobalStateProvider'
import { LanguageSave } from '../../api/LanguageSave'

type Props = {}

const Languages = (props: Props) => {
    const { setState } = useGlobalState();

    const changeLang = (data: Partial<GlobalStateInterface>) => {
      LanguageSave(data.lang as string)
      setState((prev) => ({ ...prev, ...data }));
    };

    return (
        <div style={{ marginInline: "auto" }}>
            <Grid container sx={{paddingBlock:"0"}}>
                <Grid item md={6}>
                    <Button onClick={() => {changeLang({"lang":"PL"})}} sx={{paddingBlock:"0",fontSize:"15pt"}}>🇵🇱</Button>
                </Grid>
                <Grid item md={6}>
                    <Button onClick={() => {changeLang({"lang":"EN"})}} sx={{paddingBlock:"0",fontSize:"15pt"}}>🇺🇸</Button>
                </Grid>
            </Grid>
        </div>
    )
}

export default Languages