import * as React from 'react';
import Toolbar from '@mui/material/Toolbar';
import Link from '@mui/material/Link';
import '../../static/css/Header.css';
import { AppBar, Button, Container, Divider, Slide, useScrollTrigger } from '@mui/material';

import HomeIcon from '@mui/icons-material/Home';
import FeedIcon from '@mui/icons-material/Feed';
import RateReviewIcon from '@mui/icons-material/RateReview';
import CollectionsIcon from '@mui/icons-material/Collections';
import EmailIcon from '@mui/icons-material/Email';

import Languages from './Languages';
import T from '../../api/T';
import Data from '../../utils/Data';

interface HeaderProps {
  sections: ReadonlyArray<{
    title: string;
    url: string;
  }>;
  title: string;
}

interface HideOnScrollProps {
  children: React.ReactElement;
}

function HideOnScroll(props:HideOnScrollProps) {
  const { children } = props;

  const trigger = useScrollTrigger({
    target: window,
  });

  return (
    <Slide appear={false} direction="down" in={!trigger}>
      {children}
    </Slide>
  );
}

export default function Header(props: HeaderProps) {
  const sections = Data.sections;
  return (
    <>
      <div className="desktopheader">
        <React.Fragment>
          <div style={{float:"right"}}>
          <Languages/>
          </div>
          <Container maxWidth="lg">
          <Divider style={{padding:"10px"}}>Rafał Włodarczyk - {T("author.page")}</Divider>
          <Toolbar style={{ backgroundColor: "#1976d2", borderRadius: "15pt", marginBlock: "5pt" }}
            component="nav"
            variant="dense"
            sx={{ justifyContent: 'space-between', overflowX: 'auto' }}
          >
            {sections.map((section) => (
              <Link
                color="inherit"
                noWrap
                key={section.title}
                variant="body2"
                href={section.url}
                sx={{ flexShrink: 0, textDecoration: 'none' }}
              >
                <Button variant="outlined" sx={{ color: "white" }}>{T(section.title)}</Button>
              </Link>
            ))}
          </Toolbar>
          </Container>
          &nbsp;
        </React.Fragment>
      </div>
      <div className="mobileheader" style={{zIndex:"2", marginBottom:"55pt"}}>
        <HideOnScroll {...props}>
          <AppBar sx={{backgroundColor:"#1976d2"}}>
            <Toolbar sx={{display:"grid",gridAutoFlow:"column",margin:"auto"}}>
              <Link className="mobileicon" sx={{color:"white", textAlign:"center"}} href="/">
              <HomeIcon/>
              </Link>
              <Link className="mobileicon" sx={{color:"white"}} href="/#/articles">
              <FeedIcon/>
              </Link>
              <Link className="mobileicon" sx={{color:"white"}} href="/#/gallery">
              <CollectionsIcon/>
              </Link>
              <Link className="mobileicon" sx={{color:"white"}} href="/#/poems">
              <RateReviewIcon/>
              </Link>
              <Link className="mobileicon" sx={{color:"white"}} href="/#/contact">
              <EmailIcon/>
              </Link>
            </Toolbar>
          </AppBar>
        </HideOnScroll>
      </div>
    </>
  );
}
