import { Container, Typography } from '@mui/material'
import React, { useEffect, useState } from 'react'
import Footer from '../components/general/Footer'
import Header from '../components/general/Header'
import Data from '../utils/Data'
import '../static/css/GalleryTiles.css'
import T from '../api/T'


const baseImages = [""]

const Gallery = () => {
    const [images, setImages] = useState(baseImages)

    useEffect(() => {
        const getImages = async () => {
            const serverData = await fetchImages()
            setImages(serverData)
            console.log(images)
        }
        getImages()
    }, [])

    const fetchImages = async () => {
        const res = await fetch(Data.fetchGalleryImageList)
        const json = await res.json()
        return json
    }

    return (
        <>
            <Container maxWidth="lg">
                <Header title="Rafist0" sections={Data.sections} />
                <Typography variant="h4" sx={{textAlign:"center", marginBottom:"20pt"}}>{T("photo.gallery")}</Typography>
            </Container>
            <Container maxWidth="lg">
                <div className="galleryul">
                    {
                        images.map((url) => (
                            <div className="galleryli" key={url}>
                                <img className="galleryimg" src={Data.fetchGalleryImage + url} alt={url}/>
                            </div>
                        ))
                    }
                </div>
                <Footer title="Rafał Włodarczyk 2022" description={T("footer.msg")} />
            </Container>
        </>
    )
}

export default Gallery