import { Container, Link, Typography } from '@mui/material'
import React from 'react'
import Footer from '../components/general/Footer'
import Header from '../components/general/Header'
import Data from '../utils/Data'

import GitHubIcon from '@mui/icons-material/GitHub';
import YouTubeIcon from '@mui/icons-material/YouTube';
import LinkedInIcon from '@mui/icons-material/LinkedIn';
import InstagramIcon from '@mui/icons-material/Instagram';
import EmailIcon from '@mui/icons-material/Email';
import T from '../api/T'

type Props = {}

const Contact = (props: Props) => {
  return (
    <Container maxWidth="lg" sx={{textAlign:"center",margin:"auto",alignContent:"center"}}>
    <Header title="Rafist0" sections={Data.sections} />
    <Typography variant="h4" sx={{marginBlock:"10pt"}}>{T("contact")}</Typography>
    <div style={{display:"table",margin:"0 auto"}}>
    <Link href="https://www.youtube.com/channel/UCKfsZesQpYanHjMU5yNcDNA" style={{marginBlock:"5pt",color:"white",textDecoration:"none", display: 'flex', alignItems: 'center', flexWrap: 'wrap'}}>
    <YouTubeIcon/><Typography sx={{display:"inline"}}>&nbsp;Youtube Admin1</Typography>
    </Link>
    <Link href="https://github.com/Rafisto" style={{marginBlock:"5pt",color:"white",textDecoration:"none", display: 'flex', alignItems: 'center', flexWrap: 'wrap'}}>
    <GitHubIcon/><Typography sx={{display:"inline"}}>&nbsp;GitHub @Rafisto</Typography>
    </Link>
    <Link href="https://www.instagram.com/rafist0/" style={{marginBlock:"5pt",color:"white",textDecoration:"none", display: 'flex', alignItems: 'center', flexWrap: 'wrap'}}>
    <InstagramIcon/><Typography sx={{display:"inline"}}>&nbsp;Instagram @rafist0</Typography>
    </Link>
    <Link href="https://www.linkedin.com/in/rafal-wlodarczyk/" style={{marginBlock:"5pt",color:"white",textDecoration:"none", display: 'flex', alignItems: 'center', flexWrap: 'wrap'}}>
    <LinkedInIcon/><Typography sx={{display:"inline"}}>&nbsp;LinkedIn Rafał Włodarczyk</Typography>
    </Link>
    <Link href="mailto:1.rafal.wlodarczyk@gmail.com" style={{marginBlock:"5pt",color:"white",textDecoration:"none", display: 'flex', alignItems: 'center', flexWrap: 'wrap'}}>
    <EmailIcon/><Typography sx={{display:"inline"}}>&nbsp;Email 1.rafal.wlodarczyk@gmail.com</Typography>
    </Link>
    </div>
    <Footer title="Rafał Włodarczyk 2022" description={T("footer.msg")}/>
    </Container>
  )
}

export default Contact