import { Grid, Link, Typography } from '@mui/material';
import React from 'react'
import T from '../../api/T';

interface PoemProps {
    title: string;
    date: string;
    text: string[];
}

const PoemContent = (props: PoemProps) => {
    const { title, date, text } = props;
    let lines = text.length;

    const scrollToTop = () => {
        window.scrollTo(0, 0);
    };

    return (
        <Grid item xs={12} md={8}>
            <div className="poemparent">
                <div style={{ paddingInline: "10px" }} className="poemcontent">
                    <p className="poemtitle">{title}</p>
                    <p className="poemdate">{date}</p>
                    <div style={{color:"#cccccc"}}>
                    {text.map((line: string, index: number) => {
                        var text = "";
                        let lineNumber = String(index + 1)
                        if ((index + 1) % 5 === 0) {
                            text = lineNumber + " ".repeat(String(lines).length-lineNumber.length+1);
                        }
                        else {
                            text = " ".repeat(String(lines).length+1);
                        }
                        return (
                            <p key={index} className="poemline"><span className="poemindex">{text}</span>{line}</p>
                        )
                    })}
                    </div>
                </div>
            </div>
            <Link onClick={scrollToTop} sx={{ textDecoration: 'none' }}><Typography sx={{ marginTop: "50px", textAlign: "center", fontStyle: "italic" }}>{T("poem.back.to.top")}</Typography></Link>
            <Link href="#/poems" sx={{ textDecoration: 'none' }}><Typography sx={{ marginTop: "10px", textAlign: "center", fontStyle: "italic" }}>{T("poem.list")}</Typography></Link>
        </Grid>
    )
}

export default PoemContent