import React from 'react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import remarkGfm from 'remark-gfm'
import rehypeKatex from 'rehype-katex';
import "katex/dist/katex.min.css";
import Data from './Data';
import { Container, Divider, Typography } from '@mui/material';

function MarkdownImage(props: any) {
  return (
  <>
  <Container sx={{marginBlock:"10pt",backgroundColor:"#1B1B1B",borderRadius:"10pt",width:"auto", padding:"5pt"}}>
  <Divider sx={{padding:"5pt", color:"white"}}><Typography sx={{fontSize:"12pt"}}>{props.alt}</Typography></Divider>
  <img style={{margin:"auto",display:"block",maxWidth:"100%",maxHeight:"100%"}} alt={props.alt} src={Data.fetchArticleContentImage + props.src?.split('.').splice(0, props.src?.split('.').length - 2).join('.') + "/" + props.src} />
  <Divider sx={{padding:"5pt"}}>---</Divider>
  </Container>
  </>
  )
}

export default function Markdown(props: any) {
  return <ReactMarkdown
    components={{
      img: ({ node, ...props }) => MarkdownImage(props),
    }}
    remarkPlugins={[remarkMath, remarkGfm]}
    rehypePlugins={[rehypeKatex]}
    {...props} />;
}

