import { Container, Link, Typography } from '@mui/material';
import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import Footer from '../components/general/Footer';
import Header from '../components/general/Header';
import MainArticle from '../components/blog/MainArticle';
import Data from '../utils/Data';
import T from '../api/T'

const baseArticle = {
    url: "uri",
    id: "indeks",
    title: "Trwa ładowanie artykułu",
    date: "Trwa ładowanie",
    description: "Opis artykułu",
    content: "Zawartość artykułu"
}

const Article = () => {
    let { url } = useParams();
    const [article, setArticle] = useState(baseArticle)

    useEffect(() => {
        const getArticles = async () => {
            const serverData = await fetchArticles()
            setArticle(serverData)
            console.log(article)
        }
        getArticles()
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [])

    const fetchArticles = async () => {
        const res = await fetch(Data.fetchArticle + url + ".json")
        const json = await res.json()
        return json
    }

    const scrollToTop = () => {
        window.scrollTo(0, 0);
    };

    return (
        <>
            <Container maxWidth="lg">
                <Header title="Rafist0" sections={Data.sections} />
            </Container>
            <Container maxWidth="md">
                <main style={{ textJustify: "inter-word" }}>
                    <MainArticle post={[article]} />
                </main>
                <Link onClick={scrollToTop} sx={{ textDecoration: 'none' }}><Typography sx={{ marginTop: "50px", textAlign: "center", fontStyle: "italic" }}>{T("articles.back.to.top")}</Typography></Link>
                <Link href="#/articles" sx={{ textDecoration: 'none' }}><Typography sx={{ marginTop: "10px", textAlign: "center", fontStyle: "italic" }}>{T("articles.list")}</Typography></Link>
            </Container>

            <Footer title="Rafał Włodarczyk" description={T("footer.msg")} />
        </>
    )
}

export default Article